typedef enum { STATE_ONE, STATE_TWO, STATE_THREE, STATE_FOUR, STATE_FIVE, STATE_SIX, STATE_SEVEN, STATE_EIGHT, STATE_NINE, STATE_TEN } some_state_t;
some_state_t some_FSM;
always_ff @(posedge clk or negedge resetN) begin
  if (!resetN)
    some_FSM <= some_FSM.first;
  else if (InOne & InTwo)
    some_FSM <= some_FSM.next;
end

